function merge<T extends Record<string, unknown>>(base: T, ...overs: Partial<T>[]): T {
  const out = { ...base };
  for (const over of overs) {
    for (const k of Object.keys(over) as (keyof T)[]) {
      if (over[k] !== undefined) (out as Record<string, unknown>)[k as string] = over[k];
    }
  }
  return out;
}

function build(base: T, extra?: T): Strings {
  return merge(en, base, extra || {}) as unknown as Strings;
}

